%struct.anon = type { i32, i32 }

@d = external global %struct.anon, align 4
@c = external global %struct.anon, align 4

declare void @foo()

define i32 @test_different_first() {
entry:
  %cmp = icmp eq ptr @c, @d
  br i1 %cmp, label %if.then, label %if.end

if.then:                                          ; preds = %entry
  call void @foo()
  br label %if.end

if.end:                                           ; preds = %if.then, %entry
  ret i32 0
